      "description": "Make sure the Date column is a Date type, sort the data, and ensure Close and MA30 are numeric",
      "r_code": "bitcoin_daily_5y <- bitcoin_daily_5y %>%\n  mutate(\n    Date = lubridate::ymd(Date),\n    Close = as.numeric(gsub(\"[^0-9.-]\", \"\", Close)),\n    MA30 = as.numeric(gsub(\"[^0-9.-]\", \"\", MA30))\n  ) %>%\n  arrange(Date)",
      "considerations": "If MA30 already exists as numeric you can skip its conversion; the code is safe because gsub on numeric does nothing.",
      "status": "pending"
    },
    {
      "description": "Create a signal column: 1 when Close > MA30 (long), 0 otherwise (flat)",
      "r_code": "bitcoin_daily_5y <- bitcoin_daily_5y %>%\n  mutate(Signal = ifelse(Close > MA30, 1, 0))",
      "considerations": "Signal will be used to decide whether we are invested on the next day.",
      "status": "pending"
    },
    {
      "description": "Calculate daily percentage return of the closing price and the strategy return (position lagged by one day)",
      "r_code": "bitcoin_daily_5y <- bitcoin_daily_5y %>%\n  mutate(\n    Daily_Return = (Close / lag(Close)) - 1,\n    Strategy_Return = lag(Signal) * Daily_Return\n  )",
      "considerations": "The first row will have NA for lagged values; that's fine.",
      "status": "pending"
    },
    {
      "description": "Compute cumulative profit of the strategy starting with 0 (or 1 unit of capital)",
      "r_code": "bitcoin_daily_5y <- bitcoin_daily_5y %>%\n  mutate(Cum_Profit = cumprod(1 + coalesce(Strategy_Return, 0)) - 1)",
      "considerations": "coalesce replaces NA with 0 so the first day contributes no profit.",
      "status": "pending"
    },
    {
      "description": "Scale cumulative profit to the price axis for overlaying on the price chart",
      "r_code": "local({\n  profit_min <- min(bitcoin_daily_5y$Cum_Profit, na.rm = TRUE)\n  profit_max <- max(bitcoin_daily_5y$Cum_Profit, na.rm = TRUE)\n  price_min  <- min(bitcoin_daily_5y$Close, na.rm = TRUE)\n  price_max  <- max(bitcoin_daily_5y$Close, na.rm = TRUE)\n  scale_factor <- (price_max - price_min) / (profit_max - profit_min)\n  offset <- price_min - profit_min * scale_factor\n  bitcoin_daily_5y$Profit_Scaled <- bitcoin_daily_5y$Cum_Profit * scale_factor + offset\n  # store scaling parameters for the secondary axis\n  scaling <- list(scale_factor = scale_factor, offset = offset)\n  assign(\"scaling\", scaling, envir = .GlobalEnv)\n  rm(profit_min, profit_max, price_min, price_max, scale_factor, offset, scaling)\n})",
      "considerations": "All temporary variables are removed inside the local block; only Profit_Scaled and a helper list `scaling` remain.",
      "status": "pending"
    },
    {
      "description": "Plot Close price, 30‑day MA, and the scaled cumulative profit on the same chart with a secondary axis for profit",
      "r_code": "library(ggplot2)\n\nggplot(bitcoin_daily_5y, aes(x = Date)) +\n  geom_line(aes(y = Close, colour = \"Close\")) +\n  geom_line(aes(y = MA30, colour = \"MA30\")) +\n  geom_line(aes(y = Profit_Scaled, colour = \"Cum Profit\"), linetype = \"dashed\") +\n  scale_y_continuous(\n    name = \"Price (USD)\",\n    sec.axis = dup_axis(\n      name = \"Cumulative Profit\",\n      labels = function(x) (x - scaling$offset) / scaling$scale_factor\n    )\n  ) +\n  labs(\n    title = \"Bitcoin Price, 30‑Day MA, and Trend‑Following Strategy Profit\",\n    colour = \"Series\"\n  ) +\n  theme_minimal()",
      "considerations": "The secondary axis uses the stored scaling parameters to convert back to profit values.",
      "status": "pending"
    },
    {
      "description": "Cleanup: remove temporary objects that the user did not request (Signal, Daily_Return, Strategy_Return, Cum_Profit, Profit_Scaled, scaling)",
      "r_code": "rm(Signal, Daily_Return, Strategy_Return, Cum_Profit, Profit_Scaled, scaling)",
      "considerations": "Only the original dataset `bitcoin_daily_5y` remains (now enriched with the needed columns).",
      "status": "pending"
    }
  ]
}

